Code.Terraform:
```hcl
# Terraform: Athena ワークグループのクエリ結果の暗号化を有効にします
resource "aws_athena_workgroup" "<example_resource_name>" {
  name = "<example_resource_name>"

  configuration {
    result_configuration {
      output_location = "s3://<example_bucket>/"  # クエリ結果に必要な S3 パス
      encryption_configuration {
        encryption_option = "SSE_S3"  # 重要：クエリ結果の暗号化を有効にします
      }
    }
  }
}
```
